diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 703065280096..45b0aa9437ea 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3092,7 +3092,38 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
       return getNewICmpValue(Code, IsSigned, LHS0, LHS1, Builder);
     }
   }
-
+  // For unsigned addition, the result of add is either greater than both operands
+  // (no overflow) or less than both operands (overflow). Therefore comparisons
+  // between the sum and each operand are equivalent:
+  // (icmp pred (add X, Y), X) &| (icmp pred (add X, Y), Y) -> icmp pred (add X, Y), X
+  // where pred is any of ult, ule, ugt, uge.
+  if (ICmpInst::isUnsigned(PredL) && ICmpInst::isUnsigned(PredR)) {
+    Value *AddL = nullptr, *AddR = nullptr;
+    Value *OpL = nullptr, *OpR = nullptr;
+    ICmpInst::Predicate NormPredL = PredL, NormPredR = PredR;
+    auto normalize = [&](Value *Op0, Value *Op1, ICmpInst::Predicate Pred,
+                         Value *&Add, Value *&Other, ICmpInst::Predicate &NormPred) {
+      if (match(Op0, m_Add(m_Value(), m_Value()))) {
+        Add = Op0;
+        Other = Op1;
+        NormPred = Pred;
+      } else if (match(Op1, m_Add(m_Value(), m_Value()))) {
+        Add = Op1;
+        Other = Op0;
+        NormPred = ICmpInst::getSwappedPredicate(Pred);
+      }
+    };
+    normalize(LHS0, LHS1, PredL, AddL, OpL, NormPredL);
+    normalize(RHS0, RHS1, PredR, AddR, OpR, NormPredR);
+    if (AddL && AddR && AddL == AddR && NormPredL == NormPredR) {
+      Value *X, *Y;
+      if (match(AddL, m_Add(m_Value(X), m_Value(Y)))) {
+        // Check that the other operands are the two add operands.
+        if ((OpL == X && OpR == Y) || (OpL == Y && OpR == X))
+          return LHS;
+      }
+    }
+  }
   // handle (roughly):
   // (icmp ne (A & B), C) | (icmp ne (A & D), E)
   // (icmp eq (A & B), C) & (icmp eq (A & D), E)
